const fs = require('fs');
const path = '/home/node/demo-data/support_emails.csv';
const fallback = [
  { customer_email: 'user1@example.com', subject: 'Refund request', body: 'I paid twice for invoice #123', expected_category: 'refund' },
  { customer_email: 'user2@example.com', subject: 'Login issue', body: 'Cannot access my account', expected_category: 'technical_issue' },
  { customer_email: 'user3@example.com', subject: 'Pricing inquiry', body: 'Cost for 50 users?', expected_category: 'sales' },
  { customer_email: 'user4@example.com', subject: 'Bug report', body: 'App crashes on startup', expected_category: 'technical_issue' },
  { customer_email: 'user5@example.com', subject: 'Cancel subscription', body: 'Want to cancel immediately', expected_category: 'billing' }
];
let rows = [];
try {
  const raw = fs.readFileSync(path, 'utf8');
  const lines = raw.trim().split(/\r?\n/);
  for (let i = 1; i < lines.length; i++) {
    const [customer_email, subject, body, expected_category] = lines[i].split(',');
    if (!customer_email) continue;
    rows.push({ customer_email, subject, body, expected_category, source: 'csv_demo' });
  }
} catch (e) {
  rows = fallback;
}
const crypto = require('crypto');
return rows.map((row) => {
  const input_hash = crypto.createHash('sha256').update(`${row.customer_email}|${row.subject}|${row.body}`).digest('hex');
  return { json: { ...row, valid: true, input_hash } };
});

const ticket = $input.first().json;
const src = $('Load CSV Rows').item.json;
return [{
  json: {
    ...ticket,
    input_hash: src.input_hash,
    expected_category: src.expected_category,
    ai_prompt: `Classify this B2B support ticket. Return JSON only, no markdown.
Email: ${ticket.customer_email}
Subject: ${ticket.subject}
Body: ${ticket.body}

Schema:
{
  "category": "billing" | "technical" | "sales" | "refund" | "other",
  "priority": "low" | "medium" | "high",
  "confidence": 0.0,
  "summary": "one sentence",
  "recommended_action": "escalate_human" | "auto_reply_template" | "monitor",
  "sentiment": "neutral" | "frustrated" | "urgent"
}`
  }
}];

const ticket = $('Insert Ticket').item.json;
const src = $('Load CSV Rows').item.json;
const aiRaw = $input.first().json.text || $input.first().json.output || '';
let parsed = {};
try {
  const cleaned = String(aiRaw).replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    category: 'other',
    priority: 'medium',
    confidence: 0,
    summary: 'AI response parse failed',
    recommended_action: 'escalate_human',
    sentiment: 'neutral'
  };
}
const keywords = ['refund', 'charged twice', 'down', 'outage', 'cancel immediately'];
const combined = `${ticket.subject} ${ticket.body}`.toLowerCase();
let priority = parsed.priority || 'medium';
if (keywords.some((k) => combined.includes(k)) && priority !== 'high') {
  priority = 'high';
}
const confidence = Number(parsed.confidence) || 0;
let assigned_to = null;
if (confidence < 0.6) {
  assigned_to = 'ai_low_confidence';
}
return [{
  json: {
    ticket_id: ticket.id,
    customer_email: ticket.customer_email,
    input_hash: src.input_hash,
    category: parsed.category || 'other',
    priority,
    confidence_score: confidence,
    ai_summary: parsed.summary || '',
    assigned_to,
    status: 'classified',
    notify_slack: priority === 'high' && confidence >= 0.6,
    ai_output: parsed,
    model_version: 'gpt-4o-mini',
    expected_category: src.expected_category
  }
}];

